import React, { useEffect, useState } from "react";
import axios from "axios";

function Ranking() {
  const [rankings, setRankings] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    axios
      .get("http://localhost:5000/api/rankings") // 서버 주소 확인!
      .then((res) => {
        setRankings(res.data);
        setLoading(false);
      })
      .catch((err) => {
        console.error(err);
        setLoading(false);
      });
  }, []);

  if (loading) return <p className="text-center mt-10">로딩 중...</p>;

  return (
    <div className="min-h-screen bg-gray-50 py-10 px-4">
      <h1 className="text-3xl font-bold text-center mb-8">📊 KBO 팀 순위</h1>
      <div className="max-w-3xl mx-auto bg-white rounded-lg shadow-lg overflow-hidden">
        <table className="w-full border-collapse">
          <thead>
            <tr className="bg-blue-600 text-white text-lg">
              <th className="py-3 px-4 text-left">순위</th>
              <th className="py-3 px-4 text-left">팀</th>
              <th className="py-3 px-4 text-left">승</th>
              <th className="py-3 px-4 text-left">패</th>
              <th className="py-3 px-4 text-left">무</th>
            </tr>
          </thead>
          <tbody>
            {rankings.map((team, idx) => (
              <tr
                key={idx}
                className={`border-b hover:bg-gray-100 ${
                  idx % 2 === 0 ? "bg-gray-50" : "bg-white"
                }`}
              >
                <td className="py-2 px-4 font-semibold">{team.rank}</td>
                <td className="py-2 px-4">{team.name}</td>
                <td className="py-2 px-4">{team.win}</td>
                <td className="py-2 px-4">{team.lose}</td>
                <td className="py-2 px-4">{team.draw}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

export default Ranking;
